import{_ as e,o as i,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Mobile Voice Logging","description":"","frontmatter":{},"headers":[],"relativePath":"voice-logging/mobile.md","filePath":"voice-logging/mobile.md"}'),a={name:"voice-logging/mobile.md"};function r(s,o,l,d,p,g){return i(),t("div",null,[...o[0]||(o[0]=[n('<h1 id="mobile-voice-logging" tabindex="-1">Mobile Voice Logging <a class="header-anchor" href="#mobile-voice-logging" aria-label="Permalink to &quot;Mobile Voice Logging&quot;">â€‹</a></h1><p>Mobile voice logging uses the device keyboard&#39;s microphone input. On Android with Google Voice Typing this gives unlimited recording time with no auto-timeout.</p><h2 id="android-setup-one-time" tabindex="-1">Android Setup (One Time) <a class="header-anchor" href="#android-setup-one-time" aria-label="Permalink to &quot;Android Setup (One Time)&quot;">â€‹</a></h2><ol><li>Go to <strong>Settings â†’ General Management â†’ Keyboard list and default</strong></li><li>Set <strong>Google Voice Typing</strong> as your default input method</li></ol><p>After this setup the microphone icon appears on your keyboard whenever a text field is active.</p><h2 id="how-to-use-on-android" tabindex="-1">How to Use on Android <a class="header-anchor" href="#how-to-use-on-android" aria-label="Permalink to &quot;How to Use on Android&quot;">â€‹</a></h2><ol><li>Open Voice Logger from the Game Hub</li><li>The text field activates and your keyboard appears</li><li>Tap the <strong>microphone icon</strong> on the keyboard</li><li>Speak your play description â€” you can speak as long as needed</li><li>Tap the <strong>arrow/send button</strong> when done speaking</li><li>The AI processes your description and shows the confirmation card</li></ol><p><strong>Key difference from desktop:</strong> The keyboard microphone does not auto-stop. Speak the complete play, then tap the send button manually. This gives you full control and avoids timeout issues.</p><h2 id="ios-setup" tabindex="-1">iOS Setup <a class="header-anchor" href="#ios-setup" aria-label="Permalink to &quot;iOS Setup&quot;">â€‹</a></h2><p>No setup required. Safari handles voice input natively.</p><h2 id="how-to-use-on-ios" tabindex="-1">How to Use on iOS <a class="header-anchor" href="#how-to-use-on-ios" aria-label="Permalink to &quot;How to Use on iOS&quot;">â€‹</a></h2><ol><li>Open Voice Logger from the Game Hub</li><li>Tap the <strong>microphone icon</strong> in the voice logging interface</li><li>Speak your play description</li><li>The recording stops automatically</li><li>Review and confirm on the confirmation card</li></ol><h2 id="troubleshooting-mobile" tabindex="-1">Troubleshooting Mobile <a class="header-anchor" href="#troubleshooting-mobile" aria-label="Permalink to &quot;Troubleshooting Mobile&quot;">â€‹</a></h2><p><strong>Microphone icon not showing on Android keyboard</strong> Confirm Google Voice Typing is set as your default keyboard. Some Android manufacturers use a custom keyboard as default â€” Google Voice Typing must be set explicitly.</p><p><strong>App asks for microphone permission</strong> Tap Allow. If you denied it previously go to <strong>Settings â†’ Apps â†’ Diamond Analytics â†’ Permissions â†’ Microphone â†’ Allow</strong>.</p><p><strong>Safari blocks microphone on iOS</strong> Go to <strong>Settings â†’ Safari â†’ Microphone</strong> and ensure it is set to Ask or Allow.</p>',16)])])}const u=e(a,[["render",r]]);export{h as __pageData,u as default};
